import React from 'react';
import ReactPlayer from 'react-player/lazy'

function VideoCard({url}) {
  return (
    <div className="mi-componente">
      <ReactPlayer
        url={url}
        controls
        width='100%'
        height='100%'
      />
    </div>
  );
}

export default VideoCard;
